/**
 * Cart Service Tests
 *
 * Unit tests for CartService covering:
 * - Cart CRUD operations
 * - Item management (add, update, remove)
 * - Cart totals calculation
 * - Cart transfer between sessions
 * - Discount application
 *
 * @module modules/order/__tests__/cart.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import {
  CartService,
  type Cart,
  type CartItem,
} from '@/modules/order/cart.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { EventService } from '@/core/services/event.service';

// Mock Redis functions
vi.mock('@/config/redis', () => ({
  redis: {
    exists: vi.fn(),
  },
  getCache: vi.fn(),
  setCache: vi.fn(),
  deleteCache: vi.fn(),
}));

import { redis, getCache, setCache, deleteCache } from '@/config/redis';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock EventService
 */
function createMockEventService(): {
  emitCustom: Mock;
} {
  return {
    emitCustom: vi.fn().mockResolvedValue(undefined),
  };
}

/**
 * Creates a mock cart for testing
 */
function createMockCart(overrides: Partial<Cart> = {}): Cart {
  return {
    id: 'cart_123',
    organizationId: 'org_123',
    customerId: null,
    tableId: null,
    orderType: 'DINE_IN',
    items: [],
    subtotal: 0,
    taxAmount: 0,
    discountAmount: 0,
    totalAmount: 0,
    currency: 'TRY',
    notes: null,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    ...overrides,
  };
}

/**
 * Creates a mock cart item for testing
 */
function createMockCartItem(overrides: Partial<CartItem> = {}): CartItem {
  return {
    id: 'ci_123_abc1234',
    productId: 'prod_123',
    variantId: null,
    productName: 'Test Product',
    variantName: null,
    quantity: 1,
    unitPrice: 100,
    modifiers: [],
    notes: null,
    totalPrice: 100,
    addedAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    ...overrides,
  };
}

/**
 * Creates mock product info for testing
 */
function createMockProductInfo(overrides: Partial<{
  id: string;
  name: string;
  basePrice: number;
  isAvailable: boolean;
  variants?: Array<{ id: string; name: string; price: number }>;
  modifiers?: Array<{ id: string; name: string; price: number }>;
}> = {}) {
  return {
    id: 'prod_123',
    name: 'Test Product',
    basePrice: 100,
    isAvailable: true,
    variants: [],
    modifiers: [],
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('CartService', () => {
  let service: CartService;
  let mockEventService: ReturnType<typeof createMockEventService>;

  const orgId = 'org_123';
  const cartId = 'cart_123';

  beforeEach(() => {
    vi.clearAllMocks();
    mockEventService = createMockEventService();
    service = new CartService(mockEventService as unknown as EventService);
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('getCart', () => {
    it('should return cart when found', async () => {
      // Arrange
      const cart = createMockCart();
      (getCache as Mock).mockResolvedValue(cart);

      // Act
      const result = await service.getCart(orgId, cartId);

      // Assert
      expect(result).toEqual(cart);
      expect(getCache).toHaveBeenCalledWith(`cart:${orgId}:${cartId}`);
    });

    it('should return null when cart not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);

      // Act
      const result = await service.getCart(orgId, 'nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getOrCreateCart', () => {
    it('should return existing cart when found', async () => {
      // Arrange
      const existingCart = createMockCart({ items: [createMockCartItem()] });
      (getCache as Mock).mockResolvedValue(existingCart);

      // Act
      const result = await service.getOrCreateCart(orgId, cartId);

      // Assert
      expect(result).toEqual(existingCart);
      expect(setCache).not.toHaveBeenCalled();
    });

    it('should create new cart when not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.getOrCreateCart(orgId, cartId);

      // Assert
      expect(result.id).toBe(cartId);
      expect(result.organizationId).toBe(orgId);
      expect(result.items).toHaveLength(0);
      expect(setCache).toHaveBeenCalled();
    });

    it('should set customerId when provided', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.getOrCreateCart(orgId, cartId, {
        customerId: 'cust_123',
      });

      // Assert
      expect(result.customerId).toBe('cust_123');
    });
  });

  describe('getCartItem', () => {
    it('should return cart item when found', async () => {
      // Arrange
      const item = createMockCartItem();
      const cart = createMockCart({ items: [item] });
      (getCache as Mock).mockResolvedValue(cart);

      // Act
      const result = await service.getCartItem(orgId, cartId, item.id);

      // Assert
      expect(result).toEqual(item);
    });

    it('should return null when cart not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);

      // Act
      const result = await service.getCartItem(orgId, cartId, 'item_123');

      // Assert
      expect(result).toBeNull();
    });

    it('should return null when item not in cart', async () => {
      // Arrange
      const cart = createMockCart({ items: [createMockCartItem()] });
      (getCache as Mock).mockResolvedValue(cart);

      // Act
      const result = await service.getCartItem(orgId, cartId, 'nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getItemCount', () => {
    it('should return total quantity of items', async () => {
      // Arrange
      const items = [
        createMockCartItem({ quantity: 2 }),
        createMockCartItem({ id: 'ci_456', quantity: 3 }),
      ];
      const cart = createMockCart({ items });
      (getCache as Mock).mockResolvedValue(cart);

      // Act
      const result = await service.getItemCount(orgId, cartId);

      // Assert
      expect(result).toBe(5);
    });

    it('should return 0 when cart not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);

      // Act
      const result = await service.getItemCount(orgId, cartId);

      // Assert
      expect(result).toBe(0);
    });
  });

  describe('exists', () => {
    it('should return true when cart exists', async () => {
      // Arrange
      (redis.exists as Mock).mockResolvedValue(1);

      // Act
      const result = await service.exists(orgId, cartId);

      // Assert
      expect(result).toBe(true);
    });

    it('should return false when cart does not exist', async () => {
      // Arrange
      (redis.exists as Mock).mockResolvedValue(0);

      // Act
      const result = await service.exists(orgId, cartId);

      // Assert
      expect(result).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // Add Item Tests
  // ---------------------------------------------------------------------------

  describe('addItem', () => {
    const validItemData = {
      productId: 'prod_123',
      quantity: 2,
    };

    it('should add new item to cart', async () => {
      // Arrange
      const cart = createMockCart();
      const productInfo = createMockProductInfo();
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.addItem(
        orgId,
        cartId,
        validItemData,
        productInfo
      );

      // Assert
      expect(result.item.productId).toBe('prod_123');
      expect(result.item.quantity).toBe(2);
      expect(result.cart.items).toHaveLength(1);
      expect(result.message).toContain('added');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'cart.item_added',
        expect.any(Object)
      );
    });

    it('should update quantity when adding same product', async () => {
      // Arrange
      const existingItem = createMockCartItem({
        productId: 'prod_123',
        quantity: 1,
      });
      const cart = createMockCart({ items: [existingItem] });
      const productInfo = createMockProductInfo();
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.addItem(
        orgId,
        cartId,
        { productId: 'prod_123', quantity: 2 },
        productInfo
      );

      // Assert
      expect(result.cart.items).toHaveLength(1);
      expect(result.item.quantity).toBe(3);
      expect(result.message).toContain('quantity updated');
    });

    it('should throw error when product is not available', async () => {
      // Arrange
      const cart = createMockCart();
      const productInfo = createMockProductInfo({ isAvailable: false });
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.addItem(orgId, cartId, validItemData, productInfo)
      ).rejects.toThrow(AppException);
    });

    it('should throw error when cart item limit exceeded', async () => {
      // Arrange
      const items = Array(50)
        .fill(null)
        .map((_, i) =>
          createMockCartItem({ id: `item_${i}`, productId: `prod_${i}` })
        );
      const cart = createMockCart({ items });
      const productInfo = createMockProductInfo({ id: 'prod_new' });
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.addItem(
          orgId,
          cartId,
          { productId: 'prod_new', quantity: 1 },
          productInfo
        )
      ).rejects.toThrow(AppException);
    });

    it('should use variant price when variant selected', async () => {
      // Arrange
      const cart = createMockCart();
      const productInfo = createMockProductInfo({
        basePrice: 100,
        variants: [{ id: 'var_123', name: 'Large', price: 150 }],
      });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.addItem(
        orgId,
        cartId,
        { productId: 'prod_123', variantId: 'var_123', quantity: 1 },
        productInfo
      );

      // Assert
      expect(result.item.unitPrice).toBe(150);
      expect(result.item.variantName).toBe('Large');
    });

    it('should throw error when variant not found', async () => {
      // Arrange
      const cart = createMockCart();
      const productInfo = createMockProductInfo();
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.addItem(
          orgId,
          cartId,
          { productId: 'prod_123', variantId: 'nonexistent', quantity: 1 },
          productInfo
        )
      ).rejects.toThrow(AppException);
    });

    it('should resolve modifiers correctly', async () => {
      // Arrange
      const cart = createMockCart();
      const productInfo = createMockProductInfo({
        modifiers: [{ id: 'mod_123', name: 'Extra Cheese', price: 10 }],
      });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.addItem(
        orgId,
        cartId,
        {
          productId: 'prod_123',
          quantity: 1,
          modifiers: [{ id: 'mod_123', quantity: 2 }],
        },
        productInfo
      );

      // Assert
      expect(result.item.modifiers).toHaveLength(1);
      expect(result.item.modifiers[0].name).toBe('Extra Cheese');
      expect(result.item.modifiers[0].quantity).toBe(2);
    });
  });

  // ---------------------------------------------------------------------------
  // Update Item Tests
  // ---------------------------------------------------------------------------

  describe('updateItem', () => {
    it('should update item quantity', async () => {
      // Arrange
      const item = createMockCartItem({ quantity: 1 });
      const cart = createMockCart({ items: [item] });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.updateItem(orgId, cartId, item.id, {
        quantity: 5,
      });

      // Assert
      expect(result.item.quantity).toBe(5);
      expect(result.message).toContain('updated');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'cart.item_updated',
        expect.any(Object)
      );
    });

    it('should update item notes', async () => {
      // Arrange
      const item = createMockCartItem({ notes: null });
      const cart = createMockCart({ items: [item] });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.updateItem(orgId, cartId, item.id, {
        notes: 'No onions please',
      });

      // Assert
      expect(result.item.notes).toBe('No onions please');
    });

    it('should throw error when cart not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.updateItem(orgId, cartId, 'item_123', { quantity: 2 })
      ).rejects.toThrow(AppException);
    });

    it('should throw error when item not found', async () => {
      // Arrange
      const cart = createMockCart({ items: [createMockCartItem()] });
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.updateItem(orgId, cartId, 'nonexistent', { quantity: 2 })
      ).rejects.toThrow(AppException);
    });

    it('should throw error when quantity is less than 1', async () => {
      // Arrange
      const item = createMockCartItem();
      const cart = createMockCart({ items: [item] });
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.updateItem(orgId, cartId, item.id, { quantity: 0 })
      ).rejects.toThrow(AppException);
    });

    it('should recalculate item total when quantity changes', async () => {
      // Arrange
      const item = createMockCartItem({
        quantity: 1,
        unitPrice: 100,
        totalPrice: 100,
      });
      const cart = createMockCart({ items: [item] });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.updateItem(orgId, cartId, item.id, {
        quantity: 3,
      });

      // Assert
      expect(result.item.totalPrice).toBe(300);
    });
  });

  // ---------------------------------------------------------------------------
  // Remove Item Tests
  // ---------------------------------------------------------------------------

  describe('removeItem', () => {
    it('should remove item from cart', async () => {
      // Arrange
      const item = createMockCartItem();
      const cart = createMockCart({ items: [item] });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.removeItem(orgId, cartId, item.id);

      // Assert
      expect(result.cart.items).toHaveLength(0);
      expect(result.message).toContain('removed');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'cart.item_removed',
        expect.any(Object)
      );
    });

    it('should throw error when cart not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.removeItem(orgId, cartId, 'item_123')
      ).rejects.toThrow(AppException);
    });

    it('should throw error when item not found', async () => {
      // Arrange
      const cart = createMockCart({ items: [createMockCartItem()] });
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.removeItem(orgId, cartId, 'nonexistent')
      ).rejects.toThrow(AppException);
    });

    it('should recalculate cart totals after removal', async () => {
      // Arrange
      const item1 = createMockCartItem({
        id: 'item_1',
        totalPrice: 100,
        quantity: 1,
        unitPrice: 100,
      });
      const item2 = createMockCartItem({
        id: 'item_2',
        totalPrice: 200,
        quantity: 2,
        unitPrice: 100,
      });
      const cart = createMockCart({
        items: [item1, item2],
        subtotal: 300,
        totalAmount: 330,
      });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.removeItem(orgId, cartId, 'item_1');

      // Assert
      expect(result.cart.items).toHaveLength(1);
      expect(result.cart.subtotal).toBe(200);
    });
  });

  // ---------------------------------------------------------------------------
  // Clear Cart Tests
  // ---------------------------------------------------------------------------

  describe('clearCart', () => {
    it('should clear all items from cart', async () => {
      // Arrange
      const items = [createMockCartItem(), createMockCartItem({ id: 'item_2' })];
      const cart = createMockCart({ items });
      (getCache as Mock).mockResolvedValue(cart);
      (deleteCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.clearCart(orgId, cartId);

      // Assert
      expect(result.message).toContain('cleared');
      expect(deleteCache).toHaveBeenCalled();
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'cart.cleared',
        expect.objectContaining({ itemCount: 2 })
      );
    });

    it('should return success when cart not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);

      // Act
      const result = await service.clearCart(orgId, cartId);

      // Assert
      expect(result.message).toContain('already empty');
      expect(deleteCache).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Update Cart Tests
  // ---------------------------------------------------------------------------

  describe('updateCart', () => {
    it('should update cart metadata', async () => {
      // Arrange
      const cart = createMockCart();
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.updateCart(orgId, cartId, {
        notes: 'Delivery instructions',
        orderType: 'DELIVERY',
      });

      // Assert
      expect(result.notes).toBe('Delivery instructions');
      expect(result.orderType).toBe('DELIVERY');
    });

    it('should update tableId', async () => {
      // Arrange
      const cart = createMockCart();
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.updateCart(orgId, cartId, {
        tableId: 'table_123',
      });

      // Assert
      expect(result.tableId).toBe('table_123');
    });

    it('should create cart if not exists', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.updateCart(orgId, cartId, {
        notes: 'New cart note',
      });

      // Assert
      expect(result.notes).toBe('New cart note');
      expect(result.id).toBe(cartId);
    });
  });

  // ---------------------------------------------------------------------------
  // Apply Discount Tests
  // ---------------------------------------------------------------------------

  describe('applyDiscount', () => {
    it('should apply discount to cart', async () => {
      // Arrange
      const item = createMockCartItem({
        quantity: 1,
        unitPrice: 100,
        totalPrice: 100,
      });
      const cart = createMockCart({
        items: [item],
        subtotal: 100,
        totalAmount: 110,
      });
      (getCache as Mock).mockResolvedValue(cart);
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.applyDiscount(orgId, cartId, 20);

      // Assert
      expect(result.discountAmount).toBe(20);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'cart.discount_applied',
        expect.objectContaining({ discountAmount: 20 })
      );
    });

    it('should throw error when cart not found', async () => {
      // Arrange
      (getCache as Mock).mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.applyDiscount(orgId, cartId, 20)
      ).rejects.toThrow(AppException);
    });

    it('should throw error when discount is negative', async () => {
      // Arrange
      const cart = createMockCart();
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.applyDiscount(orgId, cartId, -10)
      ).rejects.toThrow(AppException);
    });

    it('should throw error when discount exceeds subtotal', async () => {
      // Arrange
      const cart = createMockCart({ subtotal: 100 });
      (getCache as Mock).mockResolvedValue(cart);

      // Act & Assert
      await expect(
        service.applyDiscount(orgId, cartId, 150)
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Transfer Cart Tests
  // ---------------------------------------------------------------------------

  describe('transferToCustomer', () => {
    it('should transfer guest cart to customer', async () => {
      // Arrange
      const guestItem = createMockCartItem();
      const guestCart = createMockCart({
        id: 'guest_cart',
        items: [guestItem],
        customerId: null,
      });
      // Return null for customer cart (doesn't exist yet)
      (getCache as Mock)
        .mockResolvedValueOnce(guestCart) // getCart for guest
        .mockResolvedValueOnce(null); // getCart for customer
      (setCache as Mock).mockResolvedValue(undefined);
      (deleteCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.transferToCustomer(
        orgId,
        'guest_cart',
        'cust_123'
      );

      // Assert
      expect(result.customerId).toBe('cust_123');
      expect(result.items).toHaveLength(1);
      expect(deleteCache).toHaveBeenCalled();
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'cart.transferred',
        expect.objectContaining({ customerId: 'cust_123' })
      );
    });

    it('should merge items when customer cart exists', async () => {
      // Arrange
      const guestItem = createMockCartItem({
        id: 'guest_item',
        productId: 'prod_guest',
        quantity: 1,
      });
      const customerItem = createMockCartItem({
        id: 'cust_item',
        productId: 'prod_cust',
        quantity: 2,
      });
      const guestCart = createMockCart({
        id: 'guest_cart',
        items: [guestItem],
      });
      const customerCart = createMockCart({
        id: 'cust_123',
        items: [customerItem],
        customerId: 'cust_123',
      });
      (getCache as Mock)
        .mockResolvedValueOnce(guestCart)
        .mockResolvedValueOnce(customerCart);
      (setCache as Mock).mockResolvedValue(undefined);
      (deleteCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.transferToCustomer(
        orgId,
        'guest_cart',
        'cust_123'
      );

      // Assert
      expect(result.items).toHaveLength(2);
    });

    it('should merge quantities for same products', async () => {
      // Arrange
      const guestItem = createMockCartItem({
        id: 'guest_item',
        productId: 'prod_123',
        quantity: 2,
        modifiers: [],
      });
      const customerItem = createMockCartItem({
        id: 'cust_item',
        productId: 'prod_123',
        quantity: 3,
        modifiers: [],
      });
      const guestCart = createMockCart({
        id: 'guest_cart',
        items: [guestItem],
      });
      const customerCart = createMockCart({
        id: 'cust_123',
        items: [customerItem],
        customerId: 'cust_123',
      });
      (getCache as Mock)
        .mockResolvedValueOnce(guestCart)
        .mockResolvedValueOnce(customerCart);
      (setCache as Mock).mockResolvedValue(undefined);
      (deleteCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.transferToCustomer(
        orgId,
        'guest_cart',
        'cust_123'
      );

      // Assert
      expect(result.items).toHaveLength(1);
      expect(result.items[0].quantity).toBe(5);
    });

    it('should return customer cart when guest cart is empty', async () => {
      // Arrange
      const guestCart = createMockCart({ id: 'guest_cart', items: [] });
      (getCache as Mock)
        .mockResolvedValueOnce(guestCart) // getCart for guest
        .mockResolvedValueOnce(null); // getOrCreateCart check
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.transferToCustomer(
        orgId,
        'guest_cart',
        'cust_123'
      );

      // Assert
      expect(result.customerId).toBe('cust_123');
    });

    it('should create customer cart when guest cart not found', async () => {
      // Arrange
      (getCache as Mock)
        .mockResolvedValueOnce(null) // getCart for guest
        .mockResolvedValueOnce(null); // getOrCreateCart check
      (setCache as Mock).mockResolvedValue(undefined);

      // Act
      const result = await service.transferToCustomer(
        orgId,
        'guest_cart',
        'cust_123'
      );

      // Assert
